def train_model():
    """Train the spam detection model with proper validation."""
    logger.info("Training spam detection model...")
    
    texts, labels = create_training_data()
    
    # Sanitize training data consistently
    sanitized_texts = [sanitize_email_text(t) for t in texts]
    
    # Create pipeline with TF-IDF vectorizer and Logistic Regression
    pipeline = Pipeline([
        ('tfidf', TfidfVectorizer(
            max_features=5000,          # Limit vocabulary size
            ngram_range=(1, 2),         # Unigrams and bigrams
            min_df=1,                   # Minimum document frequency
            max_df=0.95,                # Maximum document frequency
            strip_accents='unicode',    # Normalize accents
            lowercase=True,             # Consistent casing
            sublinear_tf=True,          # Apply sublinear TF scaling
            token_pattern=r'(?u)\b\w+\b',  # Explicit token pattern
        )),
        ('classifier', LogisticRegression(
            C=1.0,
            max_iter=1000,
            solver='lbfgs',
            random_state=42,
        ))
    ])
    
    # Train-test split for validation
    X_train, X_test, y_train, y_test = train_test_split(
        sanitized_texts, labels, test_size=0.2, random_state=42, stratify=labels
    )
    
    pipeline.fit(X_train, y_train)
    
    # Log model performance (no sensitive data)
    train_accuracy = pipeline.score(X_train, y_train)
    test_accuracy = pipeline.score(X_test, y_test)
    logger.info("Model trained. Train accuracy: %.4f, Test accuracy: %.4f",
                train_accuracy, test_accuracy)
    
    # Save model securely
