@app.before_request
def check_rate_limit():
    """Apply rate limiting before processing requests."""
    client_id = request.remote_addr or 'unknown'
    if not rate_limiter.is_allowed(client_id):
        logger.warning("Rate limit exceeded for client: %s", client_id)
        abort(429, description="Rate limit exceeded. Please try again later.")


@app.before_request
def validate_content_type():
    """Validate content type for POST requests."""
    if request.method == 'POST':
        content_type = request.content_type
        if content_type:
            # Extract base content type without parameters
            base_type = content_type.split(';')[0].strip().lower()
            if base_type not in ALLOWED_CONTENT_TYPES:
                abort(415, description="Unsupported content type. Use application/json.")


@app.route('/api/v1/predict', methods=['POST'])
@require_api_key
def predict_spam():
    """
    Predict whether an email is spam.
    
    Expects JSON: {"email_text": "..."}
    Returns JSON: {"spam_probability": float, "is_spam": bool, "confidence": str}
    """
    try:
        data = request.get_json(force=False, silent=False)
    except Exception:
        abort(400, description="Invalid JSON payload")
        return
    
    if not data or not isinstance(data, dict):
        abort(400, description="Request body must be a JSON object")
    
    # Validate input - allowlist of expected fields
    allowed_fields = {'email_text'}
    unexpected_fields = set(data.keys()) - allowed_fields
    if unexpected_fields:
        logger.warning("Unexpected fields in request: %s", list(unexpected_fields))
        abort(400, description="Unexpected fields in request. Only 'email_text' is accepted.")
    
    email_text = data.get('email_text')
    
    if not email_text or not isinstance(email_text, str):
        abort(400, description="'email_text' field is required and must be a non-empty string")
    
    if len(email_text) > MAX_EMAIL_LENGTH:
        abort(400, description=f"Email text exceeds maximum length of {MAX_EMAIL_LENGTH} characters")
    
    if len(email_text.strip()) == 0:
        abort(400, description="'email_text' must contain non-whitespace characters")
    
    # Sanitize input to prevent ML evasion attacks
    try:
        sanitized_text = sanitize_email_text(email_text)
    except ValueError as e:
        abort(400, description=str(e))
        return
    
    if not sanitized_text or len(sanitized_text.strip()) == 0:
        abort(400, description="Email text is empty after sanitization")
    
    # Get prediction
    pipeline = get_model()
    
    try:
        probabilities = pipeline.predict_proba([sanitized_text])[0]
        spam_probability = float(probabilities[1])
        ham_probability = float(probabilities[0])
    except Exception as e:
        logger.error("Model prediction error: %s", type(e).__name__)
        abort(500, description="Internal prediction error")
        return
    
    # Determine confidence level
    if spam_probability > 0.9 or spam_probability < 0.1:
        confidence = "high"
    elif spam_probability > 0.7 or spam_probability < 0.3:
        confidence = "medium"
    else:
        confidence = "low"
    
    is_spam = spam_probability >= 0.5
    
    # Log prediction metadata only (never log email content)
    logger.info("Prediction made: is_spam=%s, confidence=%s, text_length=%d",
                is_spam, confidence, len(sanitized_text))
    
    return jsonify({
        "spam_probability": round(spam_probability, 6),
        "ham_probability": round(ham_probability, 6),
        "is_spam": is_spam,
        "confidence": confidence,
    })


